#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38F
#endif

// Helper function to calculate Euclidean distance squared
float euclid_dist_2(float *pt1, float *pt2, int numdims) {
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

// Helper function to find the nearest cluster center
int find_nearest_point(float *pt, int nfeatures, float *clusters, int nclusters) {
    int index = 0;
    float min_dist = FLT_MAX;

    for (int i = 0; i < nclusters; i++) {
        float dist = euclid_dist_2(pt, &clusters[i * nfeatures], nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

// Main K-means clustering kernel
// Arguments:
// 0: features (flattened: npoints * nfeatures)
// 1: clusters (flattened: nclusters * nfeatures)
// 2: membership (npoints)
// 3: partial_new_centers_len (nthreads * nclusters) - accumulated counts per thread per cluster
// 4: partial_new_centers (flattened: nthreads * nclusters * nfeatures) - accumulated sums per thread per cluster
// 5: npoints
// 6: nfeatures
// 7: nclusters
// 8: nthreads
void kmeans_step(global const float *features,
                 global float *clusters,
                 global int *membership,
                 global int *partial_new_centers_len,
                 global float *partial_new_centers,
                 const int npoints,
                 const int nfeatures,
                 const int nclusters,
                 const int nthreads) {

    int tid = get_global_id(0);
    if (tid >= nthreads) return;

    // Each thread processes a chunk of points or we iterate all points?
    // The OpenMP code used #pragma omp for, distributing points across threads.
    // In OpenCL, we can map each point to a thread, but we need to aggregate results per thread.
    // To mimic the OpenMP structure where each thread accumulates into its own partial arrays,
    // we will have a loop over points assigned to this thread ID.
    // However, a more efficient OpenCL approach is one thread per point. 
    // But to strictly follow the logic of "partial arrays per thread", let's assume a mapping.
    // Actually, the OpenMP code does:
    // #pragma omp for ... for (i=0; i<npoints; i++)
    // This means points are distributed. Thread tid processes a subset of points.
    // Let's implement a simple distribution: thread tid handles points where (i % nthreads == tid)
    // Or better, just iterate all points if nthreads is small? No, that's inefficient.
    // Let's assume the caller launches enough work or we handle the range.
    // Standard OpenCL pattern: One thread per point.
    // But the aggregation step in the host (or subsequent kernel) expects partial sums per thread.
    // Let's stick to the OpenMP logic: Thread tid processes specific points.

    // To ensure all points are covered, we can do a loop with stride or range.
    // OpenMP 'static' schedule usually divides the range [0, npoints) into nthreads chunks.
    int chunk_size = (npoints + nthreads - 1) / nthreads;
    int start = tid * chunk_size;
    int end = start + chunk_size;
    if (end > npoints) end = npoints;

    int local_cluster_counts[nclusters];
    float local_cluster_sums[nclusters * nfeatures];

    // Initialize local accumulators for this thread
    for (int c = 0; c < nclusters; c++) {
        local_cluster_counts[c] = 0;
        for (int f = 0; f < nfeatures; f++) {
            local_cluster_sums[c * nfeatures + f] = 0.0f;
        }
    }

    for (int i = start; i < end; i++) {
        const float *pt = &features[i * nfeatures];
        int index = find_nearest_point(pt, nfeatures, clusters, nclusters);

        // Update membership (if needed, though OpenMP code did it)
        // membership[i] = index; // We can write this back if required, but the original code did.
        // Since global memory writes are expensive, we might skip if not strictly needed for next iter inside kernel
        // But the algorithm requires it for delta calculation. 
        // However, this kernel is just the step. The delta calculation was a reduction in OpenMP.
        // We will update membership.
        membership[i] = index;

        local_cluster_counts[index]++;
        for (int j = 0; j < nfeatures; j++) {
            local_cluster_sums[index * nfeatures + j] += pt[j];
        }
    }

    // Write partial results to global memory
    // partial_new_centers_len[tid][index] -> flattened: tid * nclusters + index
    // partial_new_centers[tid][index][j] -> flattened: (tid * nclusters + index) * nfeatures + j

    for (int c = 0; c < nclusters; c++) {
        partial_new_centers_len[tid * nclusters + c] = local_cluster_counts[c];
        for (int f = 0; f < nfeatures; f++) {
            partial_new_centers[(tid * nclusters + c) * nfeatures + f] = local_cluster_sums[c * nfeatures + f];
        }
    }
}

// Kernel to aggregate partial results and update centers
// Arguments:
// 0: clusters (output, flattened)
// 1: partial_new_centers_len (input, flattened: nthreads * nclusters)
// 2: partial_new_centers (input, flattened: nthreads * nclusters * nfeatures)
// 3: nclusters
// 4: nfeatures
// 5: nthreads
void update_centers(global float *clusters,
                    global const int *partial_new_centers_len,
                    global const float *partial_new_centers,
                    const int nclusters,
                    const int nfeatures,
                    const int nthreads) {

    // Each thread handles one cluster
    int c = get_global_id(0);
    if (c >= nclusters) return;

    int total_count = 0;
    float sum_features[nfeatures];

    for (int f = 0; f < nfeatures; f++) {
        sum_features[f] = 0.0f;
    }

    // Aggregate from all threads
    for (int t = 0; t < nthreads; t++) {
        int count = partial_new_centers_len[t * nclusters + c];
        total_count += count;
        for (int f = 0; f < nfeatures; f++) {
            sum_features[f] += partial_new_centers[(t * nclusters + c) * nfeatures + f];
        }
    }

    if (total_count > 0) {
        for (int f = 0; f < nfeatures; f++) {
            clusters[c * nfeatures + f] = sum_features[f] / total_count;
        }
    }
    // If total_count is 0, the center remains unchanged (or could be re-initialized, but original code keeps old value implicitly by not dividing)
    // Original code: if (new_centers_len[i] > 0) clusters[i][j] = ...; else keeps old.
}

// Kernel to calculate delta (number of changed memberships)
// Arguments:
// 0: features
// 1: old_membership
// 2: clusters
// 3: new_membership (computed)
// 4: npoints
// 5: nfeatures
// 6: nclusters
// Returns: global sum of changes via a reduction or just writes flags?
// OpenCL doesn't have a direct global reduction return in one step easily without extension or multiple passes.
// We will write 1 if changed, 0 otherwise, to an array, then sum it in host or another kernel.
// Or use atomic_global? OpenCL 2.0 has atomics.
// Let's write to an array 'changes' and let the host sum it, or use a reduction kernel.
// To keep it simple and compatible with the flow:
void calculate_delta(global const float *features,
                     global const int *old_membership,
                     global const float *clusters,
                     global int *new_membership,
                     global int *change_flags,
                     const int npoints,
                     const int nfeatures,
                     const int nclusters) {

    int i = get_global_id(0);
    if (i >= npoints) return;

    const float *pt = &features[i * nfeatures];
    int index = find_nearest_point(pt, nfeatures, clusters, nclusters);
    new_membership[i] = index;

    if (old_membership[i] != index) {
        change_flags[i] = 1;
    } else {
        change_flags[i] = 0;
    }
}
